import numpy as np

class Piece:
    def __init__(self, color):
        self.color = color  # 'r' for red, 'b' for black
        self.king = False

    def make_king(self):
        self.king = True

class Board:
    def __init__(self):
        self.board = np.full((8, 8), None)
        self.initialize_board()

    def initialize_board(self):
        colors = ['b', 'r']
        for row in range(3):
            for col in range(8):
                if (row + col) % 2 == 1:
                    piece = Piece(colors[row])
                    self.board[row, col] = piece
        for row in range(5, 8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    piece = Piece(colors[3 - row])
                    self.board[row, col] = piece

    def print_board(self):
        for row in range(8):
            for col in range(8):
                piece = self.board[row, col]
                if piece:
                    print(piece.color.upper() + ('K' if piece.king else ''), end=' ')
                else:
                    print('.', end=' ')
            print()

    def move(self, from_pos, to_pos):
        piece = self.board[from_pos[0], from_pos[1]]
        if piece:
            self.board[to_pos[0], to_pos[1]] = piece
            self.board[from_pos[0], from_pos[1]] = None
            if self.is_king(to_pos):
                piece.make_king()
        else:
            raise ValueError("No piece at the source position")

    def is_valid_move(self, from_pos, to_pos):
        row_diff, col_diff = abs(from_pos[0] - to_pos[0]), abs(from_pos[1] - to_pos[1])
        if row_diff == 1 and col_diff == 1:
            return self.board[to_pos[0], to_pos[1]] is None
        elif row_diff == 2 and col_diff == 2:
            mid_piece = self.board[(from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2]
            if mid_piece and mid_piece.color != self.board[from_pos[0], from_pos[1]].color and self.board[to_pos[0], to_pos[1]] is None:
                return True
        return False

    def is_king(self, pos):
        piece = self.board[pos[0], pos[1]]
        if piece and (pos[0] == 0 or pos[0] == 7):
            return True
        return piece.king
