from typing import List, Tuple

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = 'B'
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = 'R'

    def print_board(self):
        for row in self.board:
            print(" ".join(f"{'-' if cell is None else cell}" for cell in row))
        print()

    def is_valid_move(self, from_pos: Tuple[int, int], to_pos: Tuple[int, int]) -> bool:
        piece = self.board[from_pos[0]][from_pos[1]]
        if piece is None or (piece == 'B' and to_pos[0] >= 7) or (piece == 'R' and to_pos[0] <= 0):
            return False
        # Implement the full rules of the game including captures and kinging
        return True

    def move_piece(self, from_pos: Tuple[int, int], to_pos: Tuple[int, int]):
        if self.is_valid_move(from_pos, to_pos):
            piece = self.board[from_pos[0]][from_pos[1]]
            self.board[to_pos[0]][to_pos[1]] = piece
            self.board[from_pos[0]][from_pos[1]] = None
            # Implement the logic for capturing and kinging
        else:
            raise ValueError("Invalid move")

    def check_winner(self):
        black_count = sum(row.count('B') for row in self.board)
        red_count = sum(row.count('R') for row in self.board)
        if black_count == 0:
            return 'Red wins'
        elif red_count == 0:
            return 'Black wins'
        else:
            return None

    def is_game_over(self):
        return self.check_winner() is not None
