        while True:
            try:
                move = input(f"Player {self.current_player}, enter your move (e.g., A1-C3): ").strip().upper()
                from_pos = tuple(map(ord, move[:2]))[::-1]
                to_pos = tuple(map(ord, move[2:4]))[::-1]
                return from_pos, to_pos
            except (IndexError, ValueError):
                print("Invalid input. Please enter a valid move.")

    def play(self):
        while True:
            self.board.print_board()
            from_pos, to_pos = self.prompt_move()
            try:
                self.board.move_piece(from_pos, to_pos)
                winner = self.board.check_winner()
                if winner is not None:
                    print(winner)
                    break
                self.current_player = 'R' if self.current_player == 'B' else 'B'
            except ValueError as e:
                print(e)

if __name__ == "__main__":
    game = Game()
    game.play()
